 1→-- Add status_category to swim_lanes for reliable status mapping
 2→-- Replaces fragile name-based matching with explicit category
 3→
 4→ALTER TABLE swim_lanes ADD COLUMN status_category TEXT NOT NULL DEFAULT '';
 5→
 6→-- Backfill existing swim lanes based on name patterns
 7→UPDATE swim_lanes SET status_category = 'todo' WHERE LOWER(name) LIKE '%to do%' OR LOWER(name) LIKE '%todo%' OR LOWER(name) = 'backlog';
 8→UPDATE swim_lanes SET status_category = 'in_progress' WHERE LOWER(name) LIKE '%progress%' OR LOWER(name) LIKE '%doing%' OR LOWER(name) LIKE '%review%';
 9→UPDATE swim_lanes SET status_category = 'done' WHERE LOWER(name) LIKE '%done%' OR LOWER(name) LIKE '%complete%' OR LOWER(name) LIKE '%finished%';
10→
11→-- Safety: default any unmatched to 'todo'
12→UPDATE swim_lanes SET status_category = 'todo' WHERE status_category = '';
13→

