283→class ApiClient {
284→  private baseURL: string
285→  private token: string | null = null
286→
287→  constructor(baseURL: string) {
288→    this.baseURL = baseURL
289→    // Load token from localStorage on initialization
290→    this.token = localStorage.getItem('auth_token')
291→  }
292→
293→  setToken(token: string | null) {
294→    this.token = token
295→    if (token) {
296→      localStorage.setItem('auth_token', token)
297→    } else {
298→      localStorage.removeItem('auth_token')
299→    }
300→  }
301→
302→  getToken(): string | null {
303→    return this.token
304→  }
305→
306→  private async request<T>(
307→    endpoint: string,
308→    options: RequestInit = {}
309→  ): Promise<T> {
310→    const url = `${this.baseURL}${endpoint}`
311→
312→    const headers: Record<string, string> = {
313→      'Content-Type': 'application/json',
314→    }
315→
316→    // Add existing headers
317→    if (options.headers) {
318→      Object.assign(headers, options.headers)
319→    }
320→
321→    // Add authorization header if token exists
322→    if (this.token) {
323→      headers['Authorization'] = `Bearer ${this.token}`
324→    }
325→
326→    const config: RequestInit = {
327→      ...options,
328→      headers,
329→    }
330→
331→    try {
332→      const response = await fetch(url, config)
333→
334→      // Handle non-JSON responses (like 204 No Content)
335→      if (response.status === 204) {
336→        return {} as T
337→      }
338→
339→      const data = await response.json()
340→
341→      if (!response.ok) {
342→        // Handle API errors
343→        const error = data as ApiError
344→        throw new Error(error.error || `HTTP ${response.status}`)
345→      }
346→
347→      return data as T
348→    } catch (error) {
349→      if (error instanceof Error) {
350→        throw error
351→      }
352→      throw new Error('An unexpected error occurred')
353→    }
354→  }
