// HandleUpdateTask updates an existing task
func (s *Server) HandleUpdateTask(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	userID := r.Context().Value(UserIDKey).(int64)
	taskID, err := strconv.ParseInt(chi.URLParam(r, "id"), 10, 64)
	if err != nil {
		respondError(w, http.StatusBadRequest, "invalid task ID", "invalid_input")
		return
	}

	var req UpdateTaskRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		respondError(w, http.StatusBadRequest, "invalid request body", "invalid_input")
		return
	}

	// Get task's project ID and verify user has access
	var projectID int64
	projectQuery := `SELECT project_id FROM tasks WHERE id = ?`
	if err := s.db.QueryRowContext(ctx, projectQuery, taskID).Scan(&projectID); err == sql.ErrNoRows {
		respondError(w, http.StatusNotFound, "task not found", "not_found")
		return
	} else if err != nil {
		respondError(w, http.StatusInternalServerError, "failed to get task project", "internal_error")
		return
	}

	// Verify user has access to the project
	hasAccess, err := s.checkProjectAccess(ctx, userID, projectID)
	if err != nil {
		respondError(w, http.StatusInternalServerError, "failed to verify project access", "internal_error")
		return
	}
	if !hasAccess {
		respondError(w, http.StatusForbidden, "access denied", "forbidden")
		return
	}

	// Build update query dynamically
	query := "UPDATE tasks SET updated_at = CURRENT_TIMESTAMP"
	args := []interface{}{}

	if req.Title != nil {
		if *req.Title == "" {
			respondError(w, http.StatusBadRequest, "task title cannot be empty", "invalid_input")
			return
		}
		if len(*req.Title) > 255 {
			respondError(w, http.StatusBadRequest, "task title is too long (max 255 characters)", "invalid_input")
			return
		}
		query += ", title = ?"
		args = append(args, *req.Title)
	}

	if req.Description != nil {
		query += ", description = ?"
		args = append(args, *req.Description)
	}

	// Swim lane/status sync: if swim_lane_id changes, derive status; if status changes, find matching lane
	if req.SwimLaneID != nil && req.Status == nil {
		// Swim lane changed — derive status from lane's status_category
		var category string
		laneQuery := `SELECT status_category FROM swim_lanes WHERE id = ? AND project_id = ?`
		if err := s.db.QueryRowContext(ctx, laneQuery, *req.SwimLaneID, projectID).Scan(&category); err == nil && category != "" {
			query += ", status = ?"
			args = append(args, category)
		}
		query += ", swim_lane_id = ?"
		args = append(args, *req.SwimLaneID)
	} else if req.Status != nil && req.SwimLaneID == nil {
		// Status changed — find first swim lane with matching status_category
		if *req.Status != "todo" && *req.Status != "in_progress" && *req.Status != "done" {
			respondError(w, http.StatusBadRequest, "invalid status (must be: todo, in_progress, or done)", "invalid_input")
			return
		}
		query += ", status = ?"
		args = append(args, *req.Status)
		var laneID int64
		laneQuery := `SELECT id FROM swim_lanes WHERE project_id = ? AND status_category = ? ORDER BY position ASC LIMIT 1`
		if err := s.db.QueryRowContext(ctx, laneQuery, projectID, *req.Status).Scan(&laneID); err == nil {
			query += ", swim_lane_id = ?"
			args = append(args, laneID)
		}
	} else if req.Status != nil && req.SwimLaneID != nil {
		// Both provided — trust swim_lane_id, derive status from it
		if *req.Status != "todo" && *req.Status != "in_progress" && *req.Status != "done" {
			respondError(w, http.StatusBadRequest, "invalid status (must be: todo, in_progress, or done)", "invalid_input")
			return
		}
		var category string
		laneQuery := `SELECT status_category FROM swim_lanes WHERE id = ? AND project_id = ?`
		if err := s.db.QueryRowContext(ctx, laneQuery, *req.SwimLaneID, projectID).Scan(&category); err == nil && category != "" {
			query += ", status = ?"
			args = append(args, category)
		} else {
			query += ", status = ?"
			args = append(args, *req.Status)
		}
		query += ", swim_lane_id = ?"
		args = append(args, *req.SwimLaneID)
	}

	if req.DueDate != nil {
		query += ", due_date = ?"
		args = append(args, *req.DueDate)
	}

	if req.Priority != nil {
		if *req.Priority != "low" && *req.Priority != "medium" && *req.Priority != "high" && *req.Priority != "urgent" {
			respondError(w, http.StatusBadRequest, "invalid priority (must be: low, medium, high, or urgent)", "invalid_input")
			return
		}
		query += ", priority = ?"
		args = append(args, *req.Priority)
	}

	if req.SprintID != nil {
		query += ", sprint_id = ?"
		args = append(args, *req.SprintID)
	}

	if req.AssigneeID != nil {
		query += ", assignee_id = ?"
		args = append(args, *req.AssigneeID)
	}

	if req.EstimatedHours != nil {
		query += ", estimated_hours = ?"
		args = append(args, *req.EstimatedHours)
	}

	if req.ActualHours != nil {
		query += ", actual_hours = ?"
		args = append(args, *req.ActualHours)
	}

	query += " WHERE id = ?"
	args = append(args, taskID)

	_, err = s.db.ExecContext(ctx, query, args...)
	if err != nil {
		respondError(w, http.StatusInternalServerError, "failed to update task", "internal_error")
		return
	}

	// Fetch the updated task with assignee, sprint, and swim lane names
	var t Task
	var priorityVal sql.NullString
	fetchQuery := `
		SELECT t.id, t.project_id, t.task_number, t.title, t.description, t.status, t.swim_lane_id, sl.name as swim_lane_name, t.due_date,
		       t.sprint_id, s.name as sprint_name,
		       t.priority, t.assignee_id, u.name as assignee_name,
		       t.estimated_hours, t.actual_hours, t.created_at, t.updated_at
		FROM tasks t
		LEFT JOIN users u ON t.assignee_id = u.id
		LEFT JOIN sprints s ON t.sprint_id = s.id
		LEFT JOIN swim_lanes sl ON t.swim_lane_id = sl.id
		WHERE t.id = ?
	`
	err = s.db.QueryRowContext(ctx, fetchQuery, taskID).Scan(
		&t.ID, &t.ProjectID, &t.TaskNumber, &t.Title, &t.Description, &t.Status, &t.SwimLaneID, &t.SwimLaneName, &t.DueDate,
		&t.SprintID, &t.SprintName, &priorityVal, &t.AssigneeID, &t.AssigneeName,
		&t.EstimatedHours, &t.ActualHours, &t.CreatedAt, &t.UpdatedAt,
	)
	if err != nil {
		respondError(w, http.StatusInternalServerError, "failed to fetch updated task", "internal_error")
		return
	}

	t.Priority = "medium" // default
	if priorityVal.Valid {
		t.Priority = priorityVal.String
	}

	// Fetch tags
	tagQuery := `
		SELECT t.id, t.user_id, t.name, t.color, t.created_at
		FROM tags t
		JOIN task_tags tt ON t.id = tt.tag_id
		WHERE tt.task_id = ?
	`
	tagRows, err := s.db.QueryContext(ctx, tagQuery, taskID)
	if err == nil {
		defer tagRows.Close()
		t.Tags = []Tag{}
		for tagRows.Next() {
			var tag Tag
			if err := tagRows.Scan(&tag.ID, &tag.UserID, &tag.Name, &tag.Color, &tag.CreatedAt); err == nil {
				t.Tags = append(t.Tags, tag)
			}
		}
	}

	respondJSON(w, http.StatusOK, t)

const saveField = async (field: string, value: any) => {
  if (!task) return
  try {
    setSaving(true)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const update: Record<string, any> = {}

    switch (field) {
      case 'title':
        if (!value?.trim()) return
        update.title = value.trim()
        break
      case 'description':
        update.description = value?.trim() || ''
        break
      case 'swim_lane_id': {
        // Backend auto-syncs status from swim lane's status_category
        update.swim_lane_id = Number(value)
        break
      }
      case 'priority':
        update.priority = value
        break
      case 'sprint_id':
        update.sprint_id = value ? parseInt(value) : null
        break
      case 'assignee_id':
        update.assignee_id = value ? parseInt(value) : null
        break
      case 'due_date':
        update.due_date = value || null
        break
      case 'estimated_hours':
        update.estimated_hours = value ? parseFloat(value) : 0
        break
      case 'actual_hours':
        update.actual_hours = value ? parseFloat(value) : 0
        break
    }

    await apiClient.updateTask(task.id!, update)
    await loadTask()
  } catch (err: unknown) {
    setError(err instanceof Error ? err.message : 'Failed to update')
  } finally {
    setSaving(false)
    setEditingField(null)
  }
}

import { useEffect, useState } from 'react'
import { useParams, useNavigate, useLocation } from 'react-router-dom'
import { DndContext, DragEndEvent, DragOverlay, DragStartEvent, PointerSensor, useSensor, useSensors } from '@dnd-kit/core'
import { api, Project, type SwimLane } from '../lib/api'
import { useLocalTasks } from '../hooks/useLocalTasks'
import type { TaskDocument } from '../lib/db/schema'

export default function ProjectDetail() {
  const { projectId } = useParams<{ projectId: string }>()
  const navigate = useNavigate()
  const [project, setProject] = useState<Project | null>(null)
  const [loadingProject, setLoadingProject] = useState(true)
  const [projectError, setProjectError] = useState<string | null>(null)
  const [swimLanes, setSwimLanes] = useState<SwimLane[]>([])
  const [loadingSwimLanes, setLoadingSwimLanes] = useState(true)

  // Use local-first tasks hook
  const {
    tasks,
    loading: loadingTasks,
    error: tasksError,
    createTask,
    updateTask,
  } = useLocalTasks(Number(projectId))

  // New task modal state
  const [showNewTaskModal, setShowNewTaskModal] = useState(false)
  const [newTaskTitle, setNewTaskTitle] = useState('')
  const [newTaskDescription, setNewTaskDescription] = useState('')
  const [newTaskDueDate, setNewTaskDueDate] = useState('')
  const [creating, setCreating] = useState(false)

  // Drag and drop state
  const [activeTask, setActiveTask] = useState<TaskDocument | null>(null)

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    })
  )

  // Load project metadata and swim lanes (tasks are handled by useLocalTasks hook)
  useEffect(() => {
    if (projectId) {
      loadProject()
      loadSwimLanes()
    }
  }, [projectId])

  const loadProject = async () => {
    try {
      setLoadingProject(true)
      setProjectError(null)
      const projectData = await api.getProject(Number(projectId))
      setProject(projectData)
    } catch (err) {
      setProjectError(err instanceof Error ? err.message : 'Failed to load project')
    } finally {
      setLoadingProject(false)
    }
  }

  const loadSwimLanes = async () => {
    try {
      setLoadingSwimLanes(true)
      const lanes = await api.getSwimLanes(Number(projectId))
      setSwimLanes(lanes.sort((a, b) => a.position - b.position))
    } catch (err) {
      console.error('Failed to load swim lanes:', err)
      // Fallback to default swim lanes if fetch fails
      setSwimLanes([
        { id: 0, project_id: Number(projectId), name: 'To Do', color: '#6B7280', position: 0, status_category: 'todo', created_at: '', updated_at: '' },
        { id: 1, project_id: Number(projectId), name: 'In Progress', color: '#3B82F6', position: 1, status_category: 'in_progress', created_at: '', updated_at: '' },
        { id: 2, project_id: Number(projectId), name: 'Done', color: '#10B981', position: 2, status_category: 'done', created_at: '', updated_at: '' },
      ])
    } finally {
      setLoadingSwimLanes(false)
    }
  }

  const handleCreateTask = async () => {
    if (!newTaskTitle.trim() || !projectId) return

    try {
      setCreating(true)
      // Optimistic create - updates UI instantly and syncs in background
      await createTask({
        title: newTaskTitle.trim(),
        description: newTaskDescription.trim() || undefined,
        status: 'todo',
        swim_lane_id: swimLanes.length > 0 ? swimLanes[0].id : undefined,
        due_date: newTaskDueDate || undefined,
      })
      setShowNewTaskModal(false)
      setNewTaskTitle('')
      setNewTaskDescription('')
      setNewTaskDueDate('')
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to create task')
    } finally {
      setCreating(false)
    }
  }

  const handleDragStart = (event: DragStartEvent) => {
    const task = tasks.find(t => t.id === event.active.id)
    setActiveTask(task || null)
  }

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event
    setActiveTask(null)

    if (!over) return

    const taskId = active.id as number
    const newSwimLaneId = Number(over.id) // Convert string ID to number

    const task = tasks.find(t => t.id === taskId)
    if (!task || task.swim_lane_id === newSwimLaneId) return

    // Find the swim lane to get the status mapping
    const swimLane = swimLanes.find(l => l.id === newSwimLaneId)
    if (!swimLane) return

    try {
      // Backend auto-syncs status from swim lane's status_category
      await updateTask(taskId, {
        swim_lane_id: newSwimLaneId,
      })
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to update task status')
    }
  }

  if (loadingProject || loadingTasks || loadingSwimLanes) {
    return (
      <div className="p-6 bg-dark-bg-base">
        <div className="animate-pulse space-y-3">
          <div className="h-6 bg-dark-bg-tertiary rounded w-1/3"></div>
          <div className="h-3 bg-dark-bg-secondary rounded w-1/2"></div>
          <div className="space-y-2 mt-6">
            <div className="h-16 bg-dark-bg-secondary rounded"></div>
            <div className="h-16 bg-dark-bg-secondary rounded"></div>
            <div className="h-16 bg-dark-bg-secondary rounded"></div>
          </div>
        </div>
      </div>
    )
  }

  if (projectError || tasksError) {
    return (
      <div className="p-6 bg-dark-bg-base">
        <div className="bg-danger-500/10 border border-danger-500/20 text-danger-400 px-4 py-3 rounded text-sm">
          {projectError || tasksError}
        </div>
      </div>
    )
  }

  // Group tasks by swim lane
  const tasksBySwimLane = swimLanes.reduce((acc, lane) => {
    acc[lane.id] = tasks.filter((t) => t.swim_lane_id === lane.id)
    return acc
  }, {} as Record<number, TaskDocument[]>)

  return (
    <DndContext sensors={sensors} onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
      <div className="h-full flex flex-col bg-dark-bg-base">
        {/* Project Header */}
        <div className="bg-dark-bg-secondary border-b border-dark-border-subtle px-4 md:px-6 py-4">
          <div className="flex flex-col sm:flex-row items-start justify-between gap-3 sm:gap-0">
            <div>
              <h1 className="text-lg font-semibold text-dark-text-primary">
                {project?.name}
              </h1>
              {project?.description && (
                <p className="mt-1 text-xs text-dark-text-secondary">{project.description}</p>
              )}
            </div>
            <div className="flex items-center gap-2">
              <button
                onClick={() => navigate(`/app/projects/${projectId}/settings`)}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-dark-bg-secondary hover:bg-dark-bg-tertiary text-dark-text-secondary hover:text-dark-text-primary text-xs font-medium rounded-md transition-colors duration-150"
                title="Project Settings"
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
                Settings
              </button>
              <button
                onClick={() => setShowNewTaskModal(true)}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-primary-500 hover:bg-primary-600 text-white text-xs font-medium rounded-md transition-colors duration-150"
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                New Task
              </button>
            </div>
          </div>

          {/* Task Stats */}
          <div className="flex gap-4 mt-3 flex-wrap">
            {swimLanes.map((lane) => (
              <div key={lane.id} className="flex items-center gap-1.5">
                <div
                  className="w-2 h-2 rounded-full"
                  style={{ backgroundColor: lane.color }}
                ></div>
                <span className="text-xs text-dark-text-secondary">
                  {tasksBySwimLane[lane.id]?.length || 0} {lane.name}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Tasks Board */}
        <div className="flex-1 overflow-y-auto overflow-x-auto p-4 md:p-6 bg-dark-bg-base">
          {tasks.length === 0 ? (
            <div className="flex items-center justify-center h-64">
              <div className="text-center">
                <svg
                  className="mx-auto h-10 w-10 text-dark-text-tertiary"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"
                  />
                </svg>
                <h3 className="mt-2 text-sm font-medium text-dark-text-primary">No tasks</h3>
                <p className="mt-1 text-xs text-dark-text-secondary">
                  Get started by creating a new task.
                </p>
              </div>
            </div>
          ) : (
            <div className="flex gap-4 overflow-x-auto pb-2 md:grid md:overflow-x-visible" style={{ gridTemplateColumns: `repeat(${swimLanes.length}, minmax(0, 1fr))` }}>
              {swimLanes.map((lane) => (
                <TaskColumn
                  key={lane.id}
                  id={lane.id.toString()}
                  title={lane.name}
                  count={tasksBySwimLane[lane.id]?.length || 0}
                  tasks={tasksBySwimLane[lane.id] || []}
                  color={lane.color}
                  projectId={projectId || ''}
                />
              ))}
            </div>
          )}
        </div>

        {/* Drag Overlay */}
        <DragOverlay>
          {activeTask ? (
            <TaskCard
              task={activeTask}
              projectId={projectId || ''}
              isDragging
            />
          ) : null}
        </DragOverlay>

        {/* New Task Modal */}
        {showNewTaskModal && (
          <div className="fixed inset-0 bg-black/70 flex items-center justify-center p-4 z-50">
            <div className="bg-dark-bg-elevated rounded-xl shadow-linear-xl max-w-md w-full p-5 border border-dark-border-subtle">
              <h2 className="text-base font-semibold text-dark-text-primary mb-4">Create New Task</h2>

              <div className="space-y-3">
                <div>
                  <label htmlFor="task-title" className="block text-xs font-medium text-dark-text-secondary mb-1">
                    Title *
                  </label>
                  <input
                    id="task-title"
                    type="text"
                    value={newTaskTitle}
                    onChange={(e) => setNewTaskTitle(e.target.value)}
                    className="w-full px-3 py-2 text-sm bg-dark-bg-secondary border border-dark-border-subtle text-dark-text-primary rounded-md focus:outline-none focus:ring-1 focus:ring-primary-500 focus:border-primary-500"
                    placeholder="Enter task title"
                    autoFocus
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' && newTaskTitle.trim()) {
                        handleCreateTask()
                      }
                    }}
                  />
                </div>

                <div>
                  <label htmlFor="task-description" className="block text-xs font-medium text-dark-text-secondary mb-1">
                    Description
                  </label>
                  <textarea
                    id="task-description"
                    value={newTaskDescription}
                    onChange={(e) => setNewTaskDescription(e.target.value)}
                    rows={3}
                    className="w-full px-3 py-2 text-sm bg-dark-bg-secondary border border-dark-border-subtle text-dark-text-primary rounded-md focus:outline-none focus:ring-1 focus:ring-primary-500 focus:border-primary-500 resize-none"
                    placeholder="Enter task description (optional)"
                  />
                </div>

                <div>
                  <label htmlFor="task-due-date" className="block text-xs font-medium text-dark-text-secondary mb-1">
                    Due Date
                  </label>
                  <input
                    id="task-due-date"
                    type="date"
                    value={newTaskDueDate}
                    onChange={(e) => setNewTaskDueDate(e.target.value)}
                    className="w-full px-3 py-2 text-sm bg-dark-bg-secondary border border-dark-border-subtle text-dark-text-primary rounded-md focus:outline-none focus:ring-1 focus:ring-primary-500 focus:border-primary-500"
                  />
                </div>
              </div>

              <div className="flex gap-2 mt-5">
                <button
                  onClick={() => {
                    setShowNewTaskModal(false)
                    setNewTaskTitle('')
                    setNewTaskDescription('')
                    setNewTaskDueDate('')
                  }}
                  className="flex-1 px-3 py-1.5 text-sm border border-dark-border-subtle text-dark-text-secondary rounded-md hover:bg-dark-bg-secondary transition-colors duration-150"
                  disabled={creating}
                >
                  Cancel
                </button>
                <button
                  onClick={handleCreateTask}
                  disabled={!newTaskTitle.trim() || creating}
                  className="flex-1 px-3 py-1.5 text-sm bg-primary-500 text-white rounded-md hover:bg-primary-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-150"
                >
                  {creating ? 'Creating...' : 'Create Task'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </DndContext>
  )
}

// Helper components
import { useDroppable } from '@dnd-kit/core'
import { useDraggable } from '@dnd-kit/core'

function TaskColumn({ id, title, count, tasks, color, projectId }: {
  id: string
  title: string
  count: number
  tasks: TaskDocument[]
  color: string
  projectId: string
}) {
  const { setNodeRef, isOver } = useDroppable({ id })

  return (
    <div ref={setNodeRef} className={`min-h-[200px] min-w-[280px] flex-shrink-0 md:min-w-0 md:flex-shrink ${isOver ? 'bg-dark-bg-tertiary/20 ring-1 ring-primary-500/30 rounded-md' : ''}`}>
      <h3 className="text-[11px] uppercase tracking-wide font-semibold text-dark-text-quaternary mb-3 flex items-center gap-2">
        <div
          className="w-1.5 h-1.5 rounded-full"
          style={{ backgroundColor: color }}
        ></div>
        {title} ({count})
      </h3>
      <div className="space-y-2">
        {tasks.map((task) => (
          <DraggableTask
            key={task.id}
            task={task}
            projectId={projectId || ''}
          />
        ))}
      </div>
    </div>
  )
}

function DraggableTask({ task, projectId }: {
  task: TaskDocument
  projectId: string
}) {
  const navigate = useNavigate()
  const location = useLocation()
  const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({
    id: task.id as number,
  })

  const style = transform ? {
    transform: `translate3d(${transform.x}px, ${transform.y}px, 0)`,
    opacity: isDragging ? 0.5 : 1,
  } : undefined

  const handleClick = () => {
    const taskIdentifier = task.task_number || task.id
    navigate(`/app/projects/${projectId}/tasks/${taskIdentifier}`, {
      state: { backgroundLocation: location },
    })
  }

  return (
    <div
      ref={setNodeRef}
      style={style}
      {...listeners}
      {...attributes}
      onClick={handleClick}
    >
      <TaskCard
        task={task}
        projectId={projectId || ''}
        isDragging={isDragging}
      />
    </div>
  )
}

function TaskCard({ task, isDragging }: {
  task: TaskDocument
  projectId?: string
  isDragging?: boolean
}) {
  return (
    <div
      className={`bg-dark-bg-primary border border-dark-border-subtle rounded-lg p-3 hover:border-dark-border-medium hover:shadow-linear-sm transition-all duration-150 cursor-pointer ${
        isDragging ? 'shadow-linear-lg rotate-1' : ''
      } ${task.status === 'done' ? 'opacity-60' : ''}`}
    >
      <div className="flex items-center gap-2">
        {task.task_number && <span className="text-xs font-mono text-dark-text-tertiary">#{task.task_number}</span>}
        <h4 className="text-sm font-medium text-dark-text-primary hover:text-primary-400 transition-colors">{task.title}</h4>
      </div>
      {task.assignee_id && (
        <div className="flex items-center gap-1.5 text-xs text-dark-text-tertiary mt-2">
          <div className="w-4 h-4 rounded-full bg-primary-500/10 flex items-center justify-center">
            <svg className="w-2.5 h-2.5 text-primary-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
            </svg>
          </div>
          <span>{task.assignee_name || `User ${task.assignee_id}`}</span>
        </div>
      )}
    </div>
  )
}

/**
 * useLocalTasks Hook
 * React hook for managing tasks with local-first optimistic updates
 */

import { useState, useEffect } from 'react'
import { useSync } from '../state/SyncContext'
import { api } from '../lib/api'
import type { TaskDocument } from '../lib/db/schema'
import type { UpdateTaskRequest } from '../lib/api'

export function useLocalTasks(projectId: number) {
  const { db, syncService } = useSync()
  const [tasks, setTasks] = useState<TaskDocument[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  // Subscribe to tasks from local database OR fetch from server
  useEffect(() => {
    if (!db) {
      // Fallback to server-side fetch when RxDB is disabled
      const fetchTasks = async () => {
        try {
          setLoading(true)
          const serverTasks = await api.getTasks(projectId)
          setTasks(serverTasks as unknown as TaskDocument[])
          setLoading(false)
        } catch (err) {
          console.error('[useLocalTasks] Server fetch error:', err)
          setError(err instanceof Error ? err.message : 'Failed to load tasks')
          setLoading(false)
        }
      }
      fetchTasks()
      return
    }

    setLoading(true)

    const subscription = db.tasks
      .find({
        selector: {
          project_id: projectId,
          _deleted: { $ne: true },
        },
        sort: [{ created_at: 'desc' }],
      })
      .$.subscribe({
        next: (docs) => {
          setTasks(docs.map(doc => doc.toJSON()))
          setLoading(false)
          setError(null)
        },
        error: (err) => {
          console.error('[useLocalTasks] Subscription error:', err)
          setError(err instanceof Error ? err.message : 'Failed to load tasks')
          setLoading(false)
        },
      })

    return () => {
      subscription.unsubscribe()
    }
  }, [db, projectId])

  /**
   * Create a new task with optimistic update
   */
  const createTask = async (data: {
    title: string
    description?: string
    status?: 'todo' | 'in_progress' | 'done'
    swim_lane_id?: number
    priority?: 'low' | 'medium' | 'high' | 'urgent'
    assignee_id?: number
    due_date?: string
  }) => {
    // Fallback to server API when RxDB is disabled
    if (!db || !syncService) {
      const newTask = await api.createTask(projectId, data)
      setTasks(prev => [newTask as unknown as TaskDocument, ...prev])
      return
    }

    // Generate temporary ID (will be replaced by server ID after sync)
    const tempId = Date.now()

    const newTask: TaskDocument = {
      id: tempId,
      project_id: projectId,
      title: data.title,
      description: data.description,
      status: data.status || 'todo',
      swim_lane_id: data.swim_lane_id,
      priority: data.priority,
      assignee_id: data.assignee_id,
      due_date: data.due_date,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      _pendingSync: true,
      _lastSynced: Date.now(),
    }

    try {
      // 1. Optimistic update: Insert into local DB immediately
      await db.tasks.insert(newTask)

      // 2. Queue for background sync
      await syncService.queueOperation('create', 'tasks', tempId, {
        ...data,
        project_id: projectId,
      })

      console.log('[useLocalTasks] Task created optimistically:', tempId)
    } catch (error) {
      console.error('[useLocalTasks] Failed to create task:', error)
      throw error
    }
  }

  /**
   * Update a task with optimistic update
   */
  const updateTask = async (taskId: number, updates: UpdateTaskRequest) => {
    // Fallback to server API when RxDB is disabled
    if (!db || !syncService) {
      const updatedTask = await api.updateTask(taskId, updates)
      setTasks(prev => prev.map(t => t.id === taskId ? updatedTask as unknown as TaskDocument : t))
      return
    }

    try {
      // Find the task
      const task = await db.tasks.findOne({ selector: { id: taskId } }).exec()
      if (!task) throw new Error('Task not found')

      // 1. Optimistic update: Update local DB immediately
      await task.update({
        $set: {
          ...updates,
          updated_at: new Date().toISOString(),
          _pendingSync: true,
        },
      })

      // 2. Queue for background sync
      await syncService.queueOperation('update', 'tasks', taskId, updates)

      console.log('[useLocalTasks] Task updated optimistically:', taskId)
    } catch (error) {
      console.error('[useLocalTasks] Failed to update task:', error)
      throw error
    }
  }

  /**
   * Delete a task with optimistic update
   */
  const deleteTask = async (taskId: number) => {
    if (!db || !syncService) throw new Error('Database not initialized')

    try {
      // Find the task
      const task = await db.tasks.findOne({ selector: { id: taskId } }).exec()
      if (!task) throw new Error('Task not found')

      // 1. Optimistic update: Mark as deleted in local DB
      await task.update({
        $set: {
          _deleted: true,
          _pendingSync: true,
        },
      })

      // 2. Queue for background sync
      await syncService.queueOperation('delete', 'tasks', taskId, {})

      console.log('[useLocalTasks] Task deleted optimistically:', taskId)
    } catch (error) {
      console.error('[useLocalTasks] Failed to delete task:', error)
      throw error
    }
  }

  /**
   * Update task status (common operation, optimized)
   */
  const updateTaskStatus = async (
    taskId: number,
    newStatus: 'todo' | 'in_progress' | 'done'
  ) => {
    await updateTask(taskId, { status: newStatus })
  }

  return {
    tasks,
    loading,
    error,
    createTask,
    updateTask,
    deleteTask,
    updateTaskStatus,
  }
}

/**
 * RxDB Database Initialization
 * Local-first database using IndexedDB
 */

import { createRxDatabase, addRxPlugin } from 'rxdb'
import { getRxStorageDexie } from 'rxdb/plugins/storage-dexie'
import { RxDBDevModePlugin } from 'rxdb/plugins/dev-mode'
import { wrappedValidateAjvStorage } from 'rxdb/plugins/validate-ajv'
import type { RxDatabase, RxCollection } from 'rxdb'

import {
  userSchema,
  projectSchema,
  taskSchema,
  sprintSchema,
  tagSchema,
  syncQueueSchema,
  type UserDocument,
  type ProjectDocument,
  type TaskDocument,
  type SprintDocument,
  type TagDocument,
  type SyncQueueDocument,
} from './schema'

// Add dev mode plugin in development
if (import.meta.env.DEV) {
  addRxPlugin(RxDBDevModePlugin)
}

// Database collections type
export type TaskAICollections = {
  users: RxCollection<UserDocument>
  projects: RxCollection<ProjectDocument>
  tasks: RxCollection<TaskDocument>
  sprints: RxCollection<SprintDocument>
  tags: RxCollection<TagDocument>
  syncqueue: RxCollection<SyncQueueDocument>
}

export type TaskAIDatabase = RxDatabase<TaskAICollections>

// Singleton database instance
let dbInstance: TaskAIDatabase | null = null

/**
 * Initialize the RxDB database
 * Creates IndexedDB with all collections
 */
export async function initDatabase(userId: number): Promise<TaskAIDatabase> {
  // Return existing instance if already initialized
  if (dbInstance) {
    return dbInstance
  }

  try {
    // Create database with AJV validator for dev mode
    const db = await createRxDatabase<TaskAICollections>({
      name: `taskai_${userId}`, // Separate DB per user
      storage: wrappedValidateAjvStorage({ storage: getRxStorageDexie() }),
      multiInstance: false, // Single tab support (can enable later)
      eventReduce: true, // Performance optimization
      cleanupPolicy: {
        minimumDeletedTime: 1000 * 60 * 60 * 24 * 7, // Keep deleted docs for 7 days
        minimumCollectionAge: 1000 * 60, // Wait 1 minute before cleanup
        runEach: 1000 * 60 * 5, // Run cleanup every 5 minutes
        awaitReplicationsInSync: true,
        waitForLeadership: true,
      },
    })

    // Add collections
    await db.addCollections({
      users: {
        schema: userSchema,
      },
      projects: {
        schema: projectSchema,
      },
      tasks: {
        schema: taskSchema,
      },
      sprints: {
        schema: sprintSchema,
      },
      tags: {
        schema: tagSchema,
      },
      syncqueue: {
        schema: syncQueueSchema,
      },
    })

    dbInstance = db

    console.log('[RxDB] Database initialized successfully')

    return db
  } catch (error) {
    console.error('[RxDB] Failed to initialize database:', error)
    throw error
  }
}

/**
 * Get the current database instance
 * Throws if database not initialized
 */
export function getDatabase(): TaskAIDatabase {
  if (!dbInstance) {
    throw new Error('Database not initialized. Call initDatabase() first.')
  }
  return dbInstance
}

/**
 * Destroy the database instance
 * Useful for logout or switching users
 */
export async function destroyDatabase(): Promise<void> {
  if (dbInstance) {
    await dbInstance.remove()
    dbInstance = null
    console.log('[RxDB] Database destroyed')
  }
}

/**
 * Clear all data from the database
 * Keeps the database instance alive
 */
export async function clearDatabase(): Promise<void> {
  const db = getDatabase()

  await Promise.all([
    db.projects.find().remove(),
    db.tasks.find().remove(),
    db.sprints.find().remove(),
    db.tags.find().remove(),
    db.syncqueue.find().remove(),
  ])

  console.log('[RxDB] Database cleared')
}

