// Import generated types from OpenAPI spec
import type { components, operations } from './api.types'

// Re-export types for convenience
export type User = components['schemas']['User']
export type AuthResponse = components['schemas']['AuthResponse']
export type SignupRequest = components['schemas']['SignupRequest']
export type LoginRequest = components['schemas']['LoginRequest']
export type Project = components['schemas']['Project']
export type Task = components['schemas']['Task'] & { task_number?: number }
export type ApiError = components['schemas']['Error']
// Types with required fields for commonly used API responses
export interface TaskComment {
  id: number
  task_id: number
  user_id: number
  user_name?: string | null
  comment: string
  created_at: string
  updated_at: string
}

export interface Sprint {
  id: number
  user_id: number
  name: string
  start_date?: string
  end_date?: string
  goal: string
  status: string
  created_at: string
  updated_at?: string
}

export interface Tag {
  id: number
  user_id: number
  name: string
  color: string
  created_at: string
}

export interface Attachment {
  id: number
  task_id: number
  filename: string
  alt_name?: string
  file_type: string
  content_type: string
  file_size: number
  cloudinary_url: string
  cloudinary_public_id: string
  created_at: string
}

export interface Invite {
  id: number
  code: string
  inviter_id: number
  invitee_id?: number
  invitee_name?: string
  used_at?: string
  expires_at?: string
  created_at: string
}

export interface ProjectMember {
  id: number
  user_id: number
  email: string
  name?: string
  user_name?: string
  role: string
  granted_by: number
  granted_at: string
}

export interface MessageResponse {
  message: string
}

export interface ProjectGitHubSettings {
  github_repo_url: string
  github_owner: string
  github_repo_name: string
  github_branch: string
  github_sync_enabled: boolean
  github_last_sync: string | null
}

export interface UserWithStats {
  id: number
  email: string
  is_admin: boolean
  created_at: string
  login_count: number
  last_login_at?: string | null
  last_login_ip?: string | null
  failed_attempts: number
  invite_count: number
}

export interface UserActivity {
  id: number
  user_id: number
  activity_type: string
  ip_address?: string | null
  user_agent?: string | null
  created_at: string
}

export interface APIKey {
  id: number
  name: string
  key_prefix: string
  created_at: string
  last_used_at?: string | null
  expires_at?: string | null
}

export interface CreateAPIKeyResponse {
  key: string
  name: string
}

export interface Team {
  id: number
  name: string
}

export interface TeamMember {
  id: number
  user_id: number
  user_name?: string
  email: string
  role: string
}

export interface TeamInvitation {
  id: number
  team_name: string
  inviter_name?: string
}

export interface TokenInvitationInfo {
  invitation_id: number
  team_name: string
  inviter_name: string
  invitee_email: string
  status: string
  requires_signup: boolean
  invite_code?: string
}

export interface StorageUsageItem {
  user_id: number
  user_name: string
  file_count: number
  total_size: number
}

// Request types (not in OpenAPI spec yet, so define them)
export interface CreateProjectRequest {
  name: string
  description?: string
}

export interface UpdateProjectRequest {
  name?: string
  description?: string
}

export interface CreateTaskRequest {
  title: string
  description?: string
  status?: 'todo' | 'in_progress' | 'done'
  swim_lane_id?: number
  due_date?: string
  sprint_id?: number
  priority?: 'low' | 'medium' | 'high' | 'urgent'
  assignee_id?: number
  estimated_hours?: number
  actual_hours?: number
  tag_ids?: number[]
}

export interface UpdateTaskRequest {
  title?: string
  description?: string
  status?: 'todo' | 'in_progress' | 'done'
  swim_lane_id?: number | null
  due_date?: string | null
  sprint_id?: number | null
  priority?: 'low' | 'medium' | 'high' | 'urgent'
  assignee_id?: number | null
  estimated_hours?: number | null
  actual_hours?: number | null
  tag_ids?: number[]
}

export interface SwimLane {
  id: number
  project_id: number
  name: string
  color: string
  position: number
  status_category: 'todo' | 'in_progress' | 'done'
  created_at: string
  updated_at: string
}

export interface CreateSwimLaneRequest {
  name: string
  color: string
  position: number
  status_category: 'todo' | 'in_progress' | 'done'
}

export interface UpdateSwimLaneRequest {
  name?: string
  color?: string
  position?: number
  status_category?: 'todo' | 'in_progress' | 'done'
}

// Helper types for API responses (using available operations)
type SignupResponse = operations['signup']['responses']['201']['content']['application/json']
type LoginResponse = operations['login']['responses']['200']['content']['application/json']
type GetCurrentUserResponse = operations['getCurrentUser']['responses']['200']['content']['application/json']

export interface EmailProviderResponse {
  id: number
  provider: string
  api_key: string
  sender_email: string
  sender_name: string
  status: 'unknown' | 'connected' | 'error' | 'suspended'
  last_checked_at: string | null
  last_error: string
  consecutive_failures: number
  created_at: string
  updated_at: string
}

export interface CloudinaryCredentialResponse {
  id: number
  user_id: number
  cloud_name: string
  api_key: string
  max_file_size_mb: number
  status: 'unknown' | 'connected' | 'error' | 'suspended'
  last_checked_at: string | null
  last_error: string
  consecutive_failures: number
  created_at: string
  updated_at: string
}

export interface Asset {
  id: number
  task_id: number
  project_id: number
  user_id: number
  filename: string
  alt_name: string
  file_type: string
  content_type: string
  file_size: number
  cloudinary_url: string
  cloudinary_public_id: string
  created_at: string
  user_name?: string
  is_owner: boolean
}

// API Client Configuration
// Use relative URL in production (served behind nginx proxy)
// or VITE_API_URL for development override
const API_BASE_URL = import.meta.env.VITE_API_URL || (
  import.meta.env.PROD ? '' : 'http://localhost:8080'
)

class ApiClient {
  private baseURL: string
  private token: string | null = null

  constructor(baseURL: string) {
    this.baseURL = baseURL
    // Load token from localStorage on initialization
    this.token = localStorage.getItem('auth_token')
  }

  setToken(token: string | null) {
    this.token = token
    if (token) {
      localStorage.setItem('auth_token', token)
    } else {
      localStorage.removeItem('auth_token')
    }
  }

  getToken(): string | null {
    return this.token
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const url = `${this.baseURL}${endpoint}`

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    }

    // Add existing headers
    if (options.headers) {
      Object.assign(headers, options.headers)
    }

    // Add authorization header if token exists
    if (this.token) {
      headers['Authorization'] = `Bearer ${this.token}`
    }

    const config: RequestInit = {
      ...options,
      headers,
    }

    try {
      const response = await fetch(url, config)

      // Handle non-JSON responses (like 204 No Content)
      if (response.status === 204) {
        return {} as T
      }

      const data = await response.json()

      if (!response.ok) {
        // Handle API errors
        const error = data as ApiError
        throw new Error(error.error || `HTTP ${response.status}`)
      }

      return data as T
    } catch (error) {
      if (error instanceof Error) {
        throw error
      }
      throw new Error('An unexpected error occurred')
    }
  }

  // Auth endpoints
  async signup(data: SignupRequest & { invite_code?: string }): Promise<SignupResponse> {
    const response = await this.request<SignupResponse>('/api/auth/signup', {
      method: 'POST',
      body: JSON.stringify(data),
    })
    if (response.token) {
      this.setToken(response.token)
    }
    return response
  }

  async login(data: LoginRequest): Promise<LoginResponse> {
    const response = await this.request<LoginResponse>('/api/auth/login', {
      method: 'POST',
      body: JSON.stringify(data),
    })
    if (response.token) {
      this.setToken(response.token)
    }
    return response
  }

  logout(): void {
    this.setToken(null)
  }

  async getCurrentUser(): Promise<GetCurrentUserResponse> {
    return this.request<GetCurrentUserResponse>('/api/me')
  }

  // Health check
  async healthCheck(): Promise<{ status: string; database?: string }> {
    return this.request('/healthz')
  }

  // Project endpoints
  async getProjects(): Promise<Project[]> {
    return this.request<Project[]>('/api/projects')
  }

  async getProject(id: number): Promise<Project> {
    return this.request<Project>('/api/projects/' + id)
  }

  async createProject(data: CreateProjectRequest): Promise<Project> {
    return this.request<Project>('/api/projects', {
      method: 'POST',
      body: JSON.stringify(data),
    })
  }

  async updateProject(id: number, data: UpdateProjectRequest): Promise<Project> {
    return this.request<Project>('/api/projects/' + id, {
      method: 'PATCH',
      body: JSON.stringify(data),
    })
  }

  async deleteProject(id: number): Promise<void> {
    return this.request<void>('/api/projects/' + id, {
      method: 'DELETE',
    })
  }

  // Task endpoints
  async getTasks(projectId: number): Promise<Task[]> {
    return this.request<Task[]>('/api/projects/' + projectId + '/tasks')
  }

  async createTask(projectId: number, data: CreateTaskRequest): Promise<Task> {
    return this.request<Task>('/api/projects/' + projectId + '/tasks', {
      method: 'POST',
      body: JSON.stringify(data),
    })
  }

  async updateTask(id: number, data: UpdateTaskRequest): Promise<Task> {
    return this.request<Task>('/api/tasks/' + id, {
      method: 'PATCH',
      body: JSON.stringify(data),
    })
  }

  async getTaskByNumber(projectId: number, taskNumber: number): Promise<Task> {
    return this.request<Task>(`/api/projects/${projectId}/tasks/${taskNumber}`)
  }

  async deleteTask(id: number): Promise<void> {
    return this.request<void>('/api/tasks/' + id, {
      method: 'DELETE',
    })
  }

  // Task comments endpoints
  async getTaskComments(taskId: number): Promise<TaskComment[]> {
    return this.request<TaskComment[]>(`/api/tasks/${taskId}/comments`)
  }

  async createTaskComment(taskId: number, comment: string): Promise<TaskComment> {
    return this.request<TaskComment>(`/api/tasks/${taskId}/comments`, {
      method: 'POST',
      body: JSON.stringify({ comment }),
    })
  }

  // Project settings - Members
  async getProjectMembers(projectId: number): Promise<ProjectMember[]> {
    return this.request<ProjectMember[]>(`/api/projects/${projectId}/members`)
  }

  async addProjectMember(projectId: number, data: { email: string; role: string }): Promise<MessageResponse> {
    return this.request<MessageResponse>(`/api/projects/${projectId}/members`, {
      method: 'POST',
      body: JSON.stringify(data),
    })
  }

  async updateProjectMember(projectId: number, memberId: number, data: { role: string }): Promise<MessageResponse> {
    return this.request<MessageResponse>(`/api/projects/${projectId}/members/${memberId}`, {
      method: 'PATCH',
      body: JSON.stringify(data),
    })
  }

  async removeProjectMember(projectId: number, memberId: number): Promise<void> {
    return this.request<void>(`/api/projects/${projectId}/members/${memberId}`, {
      method: 'DELETE',
    })
  }

  // Project settings - GitHub
  async getProjectGitHub(projectId: number): Promise<ProjectGitHubSettings> {
    return this.request<ProjectGitHubSettings>(`/api/projects/${projectId}/github`)
  }

  async updateProjectGitHub(projectId: number, data: Partial<ProjectGitHubSettings>): Promise<ProjectGitHubSettings> {
    return this.request<ProjectGitHubSettings>(`/api/projects/${projectId}/github`, {
      method: 'PATCH',
      body: JSON.stringify(data),
    })
  }

  // Admin endpoints
  async getUsers(): Promise<UserWithStats[]> {
